1	import knex, { Knex } from 'knex';
2	import { logger } from '../logging/index.js';
3	
4	let instance: Knex | null = null;
5	
6	export function getKnex(): Knex {
7	  if (!instance) {
8	    throw new Error('Database not initialized. Call initDatabase() first.');
9	  }
10	  return instance;
11	}
12	
13	export async function initDatabase(connectionString: string): Promise<Knex> {
14	  instance = knex({
15	    client: 'pg',
16	    connection: connectionString,
17	    pool: {
18	      min: 2,
19	      max: 10,
20	    },
21	    migrations: {
22	      directory: './src/infrastructure/database/migrations',
23	      extension: 'ts',
24	    },
25	    seeds: {
26	      directory: './src/infrastructure/database/seeds',
27	      extension: 'ts',
28	    },
29	  });
30	
31	  let retries = 3;
32	  while (retries > 0) {
33	    try {
34	      await instance.raw('SELECT 1');
35	      logger.info('Database connection established');
36	      return instance;
37	    } catch (error) {
38	      retries--;
39	      if (retries === 0) {
40	        logger.error({ error }, 'Failed to connect to database after 3 attempts');
41	        throw error;
42	      }
43	      logger.warn({ retriesLeft: retries }, 'Database connection failed, retrying...');
44	      await new Promise((resolve) => setTimeout(resolve, 2000));
45	    }
46	  }
47	
48	  return instance;
49	}
50	
51	export async function closeDatabase(): Promise<void> {
52	  if (instance) {
53	    await instance.destroy();
54	    instance = null;
55	    logger.info('Database connection closed');
56	  }
57	}
